businesses_key = 'var_functions.query_db:32'

reviews_2016 = locals().get(reviews_2016_key, [])
businesses = locals().get(businesses_key, [])

print('Reviews count:', len(reviews_2016))
print('Businesses count:', len(businesses))

# Date parsing function
def parse_date(date_str):
    if not date_str:
        return None
    formats = [
        '%Y-%m-%d %H:%M:%S',
        '%d %b %Y, %H:%M',
        '%B %d, %Y at %I:%M %p',
    ]
    for fmt in formats:
        try:
            return datetime.strptime(date_str.strip(), fmt)
        except:
            continue
    return None

# Filter dates and collect ratings
start_date = datetime(2016, 1, 1)
end_date = datetime(2016, 6, 30, 23, 59, 59)

business_ratings = defaultdict(list)
for review in reviews_2016:
    parsed = parse_date(review['date'])
    if parsed and start_date <= parsed <= end_date:
        business_ratings[review['business_ref']].append(int(review['rating']))

print('Businesses with reviews in period:', len(business_ratings))

# Build qualifying business info
business_info = {}
for b in businesses:
    ref = b['business_id'].replace('businessid_', 'businessref_')
    count = int(b.get('review_count', 0))
    if count >= 5:
        business_info[ref] = {
            'name': b['name'],
            'description': b.get('description', ''),
            'count': count
        }

# Calculate averages for qualifying businesses
averages = {}
for ref, ratings in business_ratings.items():
    if ref in business_info:
        avg = sum(ratings) / len(ratings)
        averages[ref] = {
            'avg': avg,
            'period_reviews': len(ratings),
            'name': business_info[ref]['name'],
            'desc': business_info[ref]['description'],
            'total_reviews': business_info[ref]['count']
        }

print('Qualifying businesses:', len(averages))

result = {}
if averages:
    best_ref = max(averages.keys(), key=lambda x: averages[x]['avg'])
    best = averages[best_ref]

    # Extract category
    desc = best['desc']
    category = 'Unknown'
    patterns = [
        r'providing a range of services in ([^.]+)\.',
        r'offers a (?:wide )?range of services,? including? ([^.]+)\.',
        r'services in ([^.]+)\.',
        r'including ([^.]+)\.',
    ]
    for pat in patterns:
        m = re.search(pat, desc, re.IGNORECASE)
        if m:
            category = m.group(1).split(',')[0].strip()
            break

    result = {
        'business_name': best['name'],
        'average_rating': round(best['avg'], 2),
        'reviews_in_period': best['period_reviews'],
        'total_reviews': best['total_reviews'],
        'category': category
    }
    print('Best business:', result)
else:
    result = {'error': 'No qualifying businesses'}

print('__RESULT__:')
print(json.dumps(result))

